import { useGesture } from '@use-gesture/react';
import clsx from 'clsx';
import { type KeyboardEventHandler } from 'react';

import {
  KNOB_HEIGHT,
  KNOB_WIDTH,
  SELECTED_AREA_RADIUS,
} from '../../overlays/constants.js';
import { knob, transparentDraggingArea } from '../SelectionArea.sty.js';

interface KnobProps {
  /** Coordinate x for knob */
  x: number;
  /** Coordinate x for knob */
  y: number;
  onKeyDown: KeyboardEventHandler;
  interactable: boolean;
  onDragMove: (x: number) => void;
  onDragStart: () => void;
  onDragEnd: () => void;
  /** Makes the element accessible through keyboard */
  focusable?: boolean;
  edgeId: string;
  hoveredEdge: string;
  pointerHandlers: {
    onPointerEnter: () => void;
    onPointerLeave: () => void;
  };
}

export const Knob = ({
  y,
  x,
  interactable,
  onKeyDown,
  focusable,
  onDragMove,
  onDragStart,
  onDragEnd,
  edgeId,
  hoveredEdge,
  pointerHandlers,
}: KnobProps) => {
  const handlers = useGesture(
    {
      ...pointerHandlers,
      onDragStart,
      onDragEnd,
      onDrag: ({ xy }: { xy: number[] }) => {
        onDragMove(xy[0]);
      },
    },
    {
      drag: {
        threshold: 2,
      },
    },
  );

  return (
    <>
      {/* Transparent dragging area */}
      <rect
        y={y - KNOB_HEIGHT / 2}
        x={x - (KNOB_WIDTH / 2) * 2}
        className={clsx(transparentDraggingArea)}
        style={{
          pointerEvents: interactable ? 'all' : 'none',
        }}
        {...handlers()}
      />
      {/* Knob */}
      <rect
        y={y}
        x={x}
        rx={SELECTED_AREA_RADIUS}
        className={clsx(
          knob,
          'knob',
          hoveredEdge === edgeId && 'knob--hovered',
        )}
        tabIndex={focusable ? 0 : -1}
        onKeyDown={onKeyDown}
        aria-label={edgeId}
      />
    </>
  );
};
